g, ctx := errgroup.WithContext(ctx)
var sendCtxErrOnce sync.Once
sendCtxErr := func() { sendCtxErrOnce.Do(func() { if err := ctx.Err(); err != nil { errCh <- err } }) }
g.Go(func() error {
  for {
    select {
    case <-ctx.Done(): sendCtxErr(); return nil
    case row, ok := <-meterRowCh:
      if !ok { sendCtxErr(); return nil }
      event, err := s.createEventFromMeterRow(m, row)
      if err != nil { errCh <- fmt.Errorf("create event from meter row: %w", err); continue }
      resultCh <- event
    }
  }
})
g.Go(func() error { return s.funnel(ctx, funnelParams{meter: m, queryParams: streaming.QueryParams{From: &params.Period.From, To: params.Period.To, WindowSize: &params.ExportWindowSize, GroupBy: []string{"subject"}}}, meterRowCh, meterRowErrCh) })
if err := g.Wait(); err != nil { return fmt.Errorf("export synthetic meter data: %w", err) }
